/**
 * Sound Effects Service using Howler.js
 *
 * Provides audio feedback for various events in Elixa.
 * Uses Web Audio API through Howler for cross-browser compatibility.
 */

import { Howl, Howler } from 'howler';

// Sound effect types
export type SoundEffect =
  | 'score_up'
  | 'score_down'
  | 'team_added'
  | 'timer_start'
  | 'timer_end'
  | 'round_start'
  | 'round_end'
  | 'elimination'
  | 'first_place'
  | 'command_success'
  | 'command_error'
  | 'listening_start'
  | 'listening_stop';

// Sound URLs - using data URIs for simple sounds to avoid external dependencies
// In production, replace with actual sound file URLs
const SOUND_CONFIG: Record<SoundEffect, { src: string; volume: number }> = {
  score_up: {
    src: 'data:audio/wav;base64,',
    volume: 0.5,
  },
  score_down: {
    src: 'data:audio/wav;base64,',
    volume: 0.4,
  },
  team_added: {
    src: 'data:audio/wav;base64,',
    volume: 0.4,
  },
  timer_start: {
    src: 'data:audio/wav;base64,',
    volume: 0.5,
  },
  timer_end: {
    src: 'data:audio/wav;base64,',
    volume: 0.6,
  },
  round_start: {
    src: 'data:audio/wav;base64,',
    volume: 0.5,
  },
  round_end: {
    src: 'data:audio/wav;base64,',
    volume: 0.5,
  },
  elimination: {
    src: 'data:audio/wav;base64,',
    volume: 0.6,
  },
  first_place: {
    src: 'data:audio/wav;base64,',
    volume: 0.7,
  },
  command_success: {
    src: 'data:audio/wav;base64,',
    volume: 0.3,
  },
  command_error: {
    src: 'data:audio/wav;base64,',
    volume: 0.4,
  },
  listening_start: {
    src: 'data:audio/wav;base64,',
    volume: 0.3,
  },
  listening_stop: {
    src: 'data:audio/wav;base64,',
    volume: 0.3,
  },
};

// Sound cache
const soundCache: Map<SoundEffect, Howl> = new Map();

// Global sound enabled state
let soundEnabled = true;

/**
 * Initialize and cache a sound
 */
function getSound(effect: SoundEffect): Howl | null {
  const config = SOUND_CONFIG[effect];
  if (!config) return null;

  if (!soundCache.has(effect)) {
    const sound = new Howl({
      src: [config.src],
      volume: config.volume,
      preload: true,
    });
    soundCache.set(effect, sound);
  }

  return soundCache.get(effect) || null;
}

/**
 * Play a sound effect
 */
export function playSound(effect: SoundEffect): void {
  if (!soundEnabled) return;

  const sound = getSound(effect);
  if (sound) {
    sound.play();
  }
}

/**
 * Enable or disable all sounds
 */
export function setSoundEnabled(enabled: boolean): void {
  soundEnabled = enabled;
  if (!enabled) {
    Howler.mute(true);
  } else {
    Howler.mute(false);
  }
}

/**
 * Check if sound is enabled
 */
export function isSoundEnabled(): boolean {
  return soundEnabled;
}

/**
 * Set global volume (0.0 to 1.0)
 */
export function setGlobalVolume(volume: number): void {
  Howler.volume(Math.max(0, Math.min(1, volume)));
}

/**
 * Preload all sounds for instant playback
 */
export function preloadSounds(): void {
  for (const effect of Object.keys(SOUND_CONFIG) as SoundEffect[]) {
    getSound(effect);
  }
}

// Auto-preload sounds when module loads
if (typeof window !== 'undefined') {
  // Defer preloading until user interaction (required for audio autoplay policies)
  const preloadOnInteraction = () => {
    preloadSounds();
    document.removeEventListener('click', preloadOnInteraction);
    document.removeEventListener('keydown', preloadOnInteraction);
  };
  document.addEventListener('click', preloadOnInteraction);
  document.addEventListener('keydown', preloadOnInteraction);
}
